style:
body {
    margin: 0;
    background: #000;
    color: #fff;
    font-family: sans-serif;
}

.MacPlayer {
    position: relative;
    width: 100%;
    background: #000;
}

.MacPlayer video {
    width: 100%;
    display: block;
}

.card {
    margin: 8px;
    background: #1a1a1a;
    border-radius: 8px;
    padding: 12px;
}

.v_title {
    font-size: 16px;
    margin: 0 0 8px 0;
}

.v_desc {
    font-size: 13px;
    color: #aaa;
}

.open_content {
    color: #fe628e;
    cursor: pointer;
}

.v_content {
    margin-top: 8px;
}

.cover img {
    width: 100%;
    border-radius: 4px;
}

.intro {
    font-size: 13px;
    color: #ddd;
}

.tab_control {
    list-style: none;
    padding: 0;
    display: flex;
    gap: 8px;
}

.tab_control li {
    padding: 4px 12px;
    background: #333;
    border-radius: 4px;
    cursor: pointer;
}

.tab_control li.current {
    background: #fe628e;
}

.play_list {
    list-style: none;
    padding: 0;
    display: flex;
    flex-wrap: wrap;
    gap: 8px;
}

.play_list li {
    padding: 6px 12px;
    background: #333;
    border-radius: 4px;
    cursor: pointer;
}

.play_list li.current {
    background: #fe628e;
}

.play_list_sort {
    cursor: pointer;
    color: #fe628e;
    margin-bottom: 8px;
}

